1540     // vp<%final.iv> = select vp<%final.min.cmp>, vp<%min.idx.next>, SENTINEL
1541     // vp<%iv.rdx> = compute-reduction-result (smax) vp<%final.iv>
1542     // vp<%cmp> = icmp ne vp<%iv.rdx>, SENTINEL
1543     // vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<0>
1544     //
1545     // Find the FindIV result pattern.
1546     auto *FindIVSelect = findFindIVSelect(FindIVPhiR->getBackedgeValue());
1547     auto *FindIVCmp = FindIVSelect->getOperand(0)->getDefiningRecipe();
1548     auto *FindIVRdxResult = cast<VPInstruction>(FindIVCmp->getOperand(0));
1549     assert(FindIVSelect->getParent() == MinOrMaxResult->getParent() &&
1550            "both results must be computed in the same block");
1551     MinOrMaxResult->moveBefore(*FindIVRdxResult->getParent(),
1552                                FindIVRdxResult->getIterator());
1553 
1554     VPBuilder B(FindIVRdxResult);
1555     VPValue *MinOrMaxExiting = MinOrMaxResult->getOperand(0);
1556     auto *FinalMinOrMaxCmp =
1557         B.createICmp(CmpInst::ICMP_EQ, MinOrMaxExiting, MinOrMaxResult);
1558     VPValue *Sentinel = FindIVCmp->getOperand(1);
1559     VPValue *LastIVExiting = FindIVRdxResult->getOperand(0);
1560     auto *FinalIVSelect =
1561         B.createSelect(FinalMinOrMaxCmp, LastIVExiting, Sentinel);
1562     FindIVRdxResult->setOperand(0, FinalIVSelect);
1563   }
1564   return true;
